/**
 * Script para adicionar a coluna bio na tabela users
 * Para executar: npx tsx add-bio-column.ts
 */

import { Pool } from '@neondatabase/serverless';
import dotenv from 'dotenv';

dotenv.config();

if (!process.env.DATABASE_URL) {
  throw new Error('DATABASE_URL não encontrada');
}

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function addBioColumn() {
  try {
    console.log('Adicionando coluna bio na tabela users...');

    // Adicionar a coluna bio se não existir
    await pool.query(`
      ALTER TABLE users 
      ADD COLUMN IF NOT EXISTS bio TEXT;
    `);

    console.log('Coluna bio adicionada com sucesso!');

    // Verificar se a coluna foi criada
    const result = await pool.query(`
      SELECT column_name, data_type 
      FROM information_schema.columns 
      WHERE table_name = 'users' AND column_name = 'bio';
    `);

    if (result.rows.length > 0) {
      console.log('Confirmado: Coluna bio existe na tabela users');
      console.log('Tipo de dados:', result.rows[0].data_type);
    } else {
      console.log('Erro: Coluna bio não foi encontrada após criação');
    }

  } catch (error) {
    console.error('Erro ao adicionar coluna bio:', error);
  } finally {
    await pool.end();
  }
}

addBioColumn();

add-delete-policy-categories.ts.content:
/**
 * Script para adicionar uma política de exclusão (DELETE) para a tabela categorias no Supabase
 * 
 * Este script verifica se RLS está ativado e adiciona uma policy que permite a exclusão de categorias
 * 
 * Para executar:
 * npx tsx add-delete-policy-categories.ts
 */

import { createClient } from '@supabase/supabase-js';
import dotenv from 'dotenv';

dotenv.config();

// Obtendo a URL e chave do Supabase das variáveis de ambiente
const supabaseUrl = process.env.SUPABASE_URL;
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !supabaseKey) {
  console.error('Erro: SUPABASE_URL e SUPABASE_SERVICE_ROLE_KEY devem estar definidos nas variáveis de ambiente');
  process.exit(1);
}

// Criando o cliente Supabase com a chave de serviço (role key) que tem permissões de admin
const supabase = createClient(supabaseUrl, supabaseKey);

async function checkAndAddDeletePolicy() {
  try {
    console.log('Verificando a tabela categorias no Supabase...');

    // Verificar se a tabela existe e tem RLS ativado
    const { data: tableInfo, error: tableError } = await supabase
      .rpc('get_table_info', { target_table: 'categorias' });

    if (tableError) {
      console.error('Erro ao verificar a tabela:', tableError);
      return;
    }

    if (!tableInfo || tableInfo.length === 0) {
      console.error('A tabela categorias não foi encontrada');
      return;
    }

    const table = tableInfo[0];
    console.log(`Tabela categorias encontrada. RLS ativado: ${table.rls_enabled}`);

    // Verificar se já existe uma política de DELETE
    const { data: policies, error: policiesError } = await supabase
      .from('pg_policies')
      .select('*')
      .eq('tablename', 'categorias')
      .eq('cmd', 'DELETE');

    if (policiesError) {
      console.error('Erro ao verificar as políticas:', policiesError);
      return;
    }

    if (policies && policies.length > 0) {
      console.log('Já existe uma política de DELETE para a tabela categorias:');
      policies.forEach(policy => {
        console.log(`- ${policy.policyname}: ${policy.qual}`);
      });
    } else {
      console.log('Nenhuma política de DELETE encontrada para a tabela categorias');

      // Adicionar política de DELETE
      console.log('Adicionando política de DELETE...');

      // Utilizando SQL diretamente para adicionar a política
      const { error: createPolicyError } = await supabase
        .rpc('execute_sql', {
          sql: `
            create policy "Permitir exclusão de categorias"
            on public.categorias
            for delete
            to authenticated
            using (true);
          `
        });

      if (createPolicyError) {
        console.error('Erro ao criar a política:', createPolicyError);
        return;
      }

      console.log('Política de DELETE adicionada com sucesso!');
    }

    // Verificar a configuração da chave estrangeira entre posts e categorias
    console.log('Verificando a chave estrangeira entre posts e categorias...');

    const { data: fkData, error: fkError } = await supabase
      .rpc('execute_sql', {
        sql: `
          SELECT tc.constraint_name, 
                 tc.table_name, 
                 kcu.column_name, 
                 ccu.table_name AS foreign_table_name, 
                 ccu.column_name AS foreign_column_name,
                 rc.delete_rule
          FROM information_schema.table_constraints AS tc 
          JOIN information_schema.key_column_usage AS kcu
            ON tc.constraint_name = kcu.constraint_name
          JOIN information_schema.constraint_column_usage AS ccu 
            ON ccu.constraint_name = tc.constraint_name
          JOIN information_schema.referential_constraints AS rc
            ON rc.constraint_name = tc.constraint_name
          WHERE tc.constraint_type = 'FOREIGN KEY' 
            AND ccu.table_name = 'categorias'
            AND tc.table_name = 'posts';
        `
      });

    if (fkError) {
      console.error('Erro ao verificar a chave estrangeira:', fkError);
      return;
    }

    if (fkData && fkData.result && fkData.result.length > 0) {
      const fk = fkData.result[0];
      console.log(`Chave estrangeira encontrada: ${fk.constraint_name}`);
      console.log(`Regra de exclusão atual: ${fk.delete_rule}`);

      if (fk.delete_rule === 'RESTRICT' || fk.delete_rule === 'NO ACTION') {
        console.log('Atualizando a regra de exclusão para SET NULL...');

        // Obtém o nome da constraint
        const constraintName = fk.constraint_name;

        // Altera a chave estrangeira para ON DELETE SET NULL
        const { error: alterFkError } = await supabase
          .rpc('execute_sql', {
            sql: `
              ALTER TABLE public.posts 
              DROP CONSTRAINT ${constraintName},
              ADD CONSTRAINT ${constraintName} 
              FOREIGN KEY (category_id) 
              REFERENCES public.categorias(id)
              ON DELETE SET NULL;
            `
          });

        if (alterFkError) {
          console.error('Erro ao alterar a chave estrangeira:', alterFkError);
          return;
        }

        console.log('Chave estrangeira alterada com sucesso para ON DELETE SET NULL!');
      } else if (fk.delete_rule === 'SET NULL') {
        console.log('A chave estrangeira já está configurada com ON DELETE SET NULL');
      } else {
        console.log(`A chave estrangeira tem uma regra de exclusão diferente: ${fk.delete_rule}`);
      }
    } else {
      console.log('Nenhuma chave estrangeira encontrada entre posts e categorias');
    }

    console.log('Verificação e ajustes concluídos com sucesso!');

  } catch (error) {
    console.error('Erro inesperado:', error);
  }
}

// Executar a função principal
checkAndAddDeletePolicy();

add-hotmart-plan-fields.ts.content:
/**
 * Script para adicionar campos dos planos reais do Hotmart na tabela subscriptions
 * 
 * Para executar: npx tsx add-hotmart-plan-fields.ts
 */

import { Pool } from '@neondatabase/serverless';
import * as dotenv from 'dotenv';

dotenv.config();

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function addHotmartPlanFields() {
  console.log('🔧 Adicionando campos de planos reais do Hotmart na tabela subscriptions...');

  try {
    // Verificar se as colunas já existem
    const checkColumns = await pool.query(`
      SELECT column_name 
      FROM information_schema.columns 
      WHERE table_name = 'subscriptions' 
      AND column_name IN ('hotmart_plan_id', 'hotmart_plan_name', 'hotmart_plan_price', 'hotmart_currency')
    `);

    const existingColumns = checkColumns.rows.map(row => row.column_name);
    console.log('📋 Colunas existentes:', existingColumns);

    // Adicionar colunas faltantes
    const columnsToAdd = [
      { name: 'hotmart_plan_id', type: 'TEXT', description: 'ID real do plano no Hotmart' },
      { name: 'hotmart_plan_name', type: 'TEXT', description: 'Nome real do plano no Hotmart' },
      { name: 'hotmart_plan_price', type: 'DECIMAL(10,2)', description: 'Preço real do plano' },
      { name: 'hotmart_currency', type: 'VARCHAR(3) DEFAULT \'BRL\'', description: 'Moeda do plano' }
    ];

    for (const column of columnsToAdd) {
      if (!existingColumns.includes(column.name)) {
        console.log(`➕ Adicionando coluna ${column.name}...`);

        await pool.query(`
          ALTER TABLE subscriptions 
          ADD COLUMN ${column.name} ${column.type}
        `);

        console.log(`✅ Coluna ${column.name} adicionada com sucesso`);
      } else {
        console.log(`⏭️ Coluna ${column.name} já existe`);
      }
    }

    // Verificar a estrutura final da tabela
    const finalStructure = await pool.query(`
      SELECT column_name, data_type, is_nullable, column_default
      FROM information_schema.columns 
      WHERE table_name = 'subscriptions' 
      ORDER BY ordinal_position
    `);

    console.log('\n📊 Estrutura final da tabela subscriptions:');
    finalStructure.rows.forEach(row => {
      console.log(`  - ${row.column_name}: ${row.data_type} ${row.is_nullable === 'YES' ? '(nullable)' : '(not null)'}`);
    });

    console.log('\n🎯 Campos de planos reais do Hotmart adicionados com sucesso!');
    console.log('Agora o webhook pode capturar e salvar:');
    console.log('  - ID real do plano no Hotmart');
    console.log('  - Nome completo do plano');
    console.log('  - Preço real pago');
    console.log('  - Moeda da transação');

  } catch (error: any) {
    console.error('❌ Erro ao adicionar campos:', error);
    console.error('Stack trace:', error.stack);
  } finally {
    await pool.end();
  }
}

addHotmartPlanFields();

add-login-background-field.ts.content:
/**
 * Script para adicionar campos de personalização na tabela settings
 * Adiciona logo_url e login_background_url para personalização da plataforma
 * 
 * Para executar: npx tsx add-login-background-field.ts
 */

import { neon } from '@neondatabase/serverless';

const sql = neon(process.env.DATABASE_URL!);

async function addPersonalizationFields() {
  try {
    console.log('Adicionando campos de personalização na tabela settings...');

    // Inserir logo_url se não existir
    await sql`
      INSERT INTO settings (key, value, description)
      VALUES ('logo_url', '', 'URL do logo da plataforma armazenado no Supabase Storage')
      ON CONFLICT (key) DO NOTHING
    `;

    // Inserir login_background_url se não existir
    await sql`
      INSERT INTO settings (key, value, description)
      VALUES ('login_background_url', '', 'URL da imagem de fundo da página de login armazenada no Supabase Storage')
      ON CONFLICT (key) DO NOTHING
    `;

    console.log('✅ Campos de personalização adicionados com sucesso!');

    // Verificar se foram inseridos
    const settings = await sql`
      SELECT key, value, description 
      FROM settings 
      WHERE key IN ('logo_url', 'login_background_url')
      ORDER BY key
    `;

    console.log('Configurações existentes:');
    settings.forEach(setting => {
      console.log(`- ${setting.key}: ${setting.value || '(vazio)'}`);
    });

  } catch (error) {
    console.error('❌ Erro ao adicionar campos de personalização:', error);
  }
}

addPersonalizationFields();

add-missing-db-fields.ts.content:
/**
 * Script para adicionar campos faltantes no banco de dados
 * 
 * 1. Campo telefone na tabela users
 * 2. Campos is_pro e license_type na tabela posts
 * 
 * Para executar:
 * npx tsx add-missing-db-fields.ts
 */

import { Pool } from '@neondatabase/serverless';
import { config } from 'dotenv';
import { neonConfig } from '@neondatabase/serverless';
import * as ws from 'ws';

// Configuração para o WebSocket
neonConfig.webSocketConstructor = ws.WebSocket;

// Carrega variáveis de ambiente
config();

async function addMissingFields() {
  console.log("Iniciando adição de campos faltantes no banco de dados...");

  const pool = new Pool({
    connectionString: process.env.DATABASE_URL
  });

  try {
    // 1. Verifica e adiciona coluna telefone na tabela users
    const checkTelefoneResult = await pool.query(`
      SELECT column_name 
      FROM information_schema.columns 
      WHERE table_name = 'users' AND column_name = 'telefone'
    `);

    if (checkTelefoneResult.rows.length === 0) {
      console.log("Adicionando coluna 'telefone' à tabela users...");
      await pool.query(`
        ALTER TABLE users
        ADD COLUMN telefone TEXT
      `);
      console.log("Campo 'telefone' adicionado com sucesso à tabela users!");
    } else {
      console.log("A coluna 'telefone' já existe na tabela users.");
    }

    // 2. Verifica e adiciona coluna is_pro na tabela posts
    const checkIsProResult = await pool.query(`
      SELECT column_name 
      FROM information_schema.columns 
      WHERE table_name = 'posts' AND column_name = 'is_pro'
    `);

    if (checkIsProResult.rows.length === 0) {
      console.log("Adicionando coluna 'is_pro' à tabela posts...");
      await pool.query(`
        ALTER TABLE posts
        ADD COLUMN is_pro BOOLEAN DEFAULT FALSE
      `);
      console.log("Campo 'is_pro' adicionado com sucesso à tabela posts!");
    } else {
      console.log("A coluna 'is_pro' já existe na tabela posts.");
    }

    // 3. Verifica e adiciona coluna license_type na tabela posts
    const checkLicenseTypeResult = await pool.query(`
      SELECT column_name 
      FROM information_schema.columns 
      WHERE table_name = 'posts' AND column_name = 'license_type'
    `);

    if (checkLicenseTypeResult.rows.length === 0) {
      console.log("Adicionando coluna 'license_type' à tabela posts...");
      await pool.query(`
        ALTER TABLE posts
        ADD COLUMN license_type TEXT DEFAULT 'free'
      `);
      console.log("Campo 'license_type' adicionado com sucesso à tabela posts!");
    } else {
      console.log("A coluna 'license_type' já existe na tabela posts.");
    }

    // 4. Atualiza os valores de is_pro e license_type para posts que contêm 'premium' no título
    console.log("Atualizando status premium dos posts existentes...");

    await pool.query(`
      UPDATE posts
      SET is_pro = TRUE, license_type = 'premium'
      WHERE (
        LOWER(title) LIKE '%premium%' OR 
        LOWER(description) LIKE '%premium%'
      ) AND (is_pro IS NULL OR is_pro = FALSE)
    `);

    console.log("Status premium dos posts atualizado com sucesso!");

  } catch (error) {
    console.error("Erro ao adicionar campos faltantes:", error);
  } finally {
    await pool.end();
  }
}

addMissingFields()
  .then(() => console.log("Processo finalizado com sucesso."))
  .catch(error => console.error("Erro:", error));

