/**
 * Script para verificar buckets do Supabase Storage
 * Para executar: npx tsx check-supabase-buckets.ts
 */

import { createClient } from '@supabase/supabase-js';
import * as dotenv from 'dotenv';

// Carregar variáveis de ambiente
dotenv.config();

const supabaseUrl = process.env.VITE_SUPABASE_URL?.replace(/"/g, '');
const supabaseKey = process.env.VITE_SUPABASE_KEY?.replace(/"/g, '');

if (!supabaseUrl || !supabaseKey) {
  console.error('Variáveis VITE_SUPABASE_URL e VITE_SUPABASE_KEY são obrigatórias');
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);

async function checkBuckets() {
  try {
    console.log('🔍 Verificando buckets do Supabase Storage...\n');

    const { data: buckets, error } = await supabase.storage.listBuckets();

    if (error) {
      console.error('❌ Erro ao listar buckets:', error);
      return;
    }

    console.log('📁 Buckets existentes:');
    buckets.forEach(bucket => {
      console.log(`  - ${bucket.name} (público: ${bucket.public})`);
    });

    // Verificar conteúdo do bucket perfis
    console.log('\n👤 Verificando bucket "perfis":');
    const { data: perfilFiles, error: perfilError } = await supabase.storage
      .from('perfis')
      .list('', { limit: 10, sortBy: { column: 'created_at', order: 'desc' } });

    if (!perfilError && perfilFiles && perfilFiles.length > 0) {
      console.log('  Arquivos encontrados:');
      perfilFiles.forEach(file => {
        if (file.name) {
          console.log(`    - ${file.name} (${(file.metadata?.size || 0 / 1024).toFixed(1)}KB)`);
        }
      });
    } else {
      console.log('  ⚠️  Bucket vazio ou erro:', perfilError?.message || 'sem arquivos');
    }

    // Verificar conteúdo do bucket logos
    console.log('\n🎨 Verificando bucket "logos":');
    const { data: logoFiles, error: logoError } = await supabase.storage
      .from('logos')
      .list('', { limit: 10, sortBy: { column: 'created_at', order: 'desc' } });

    if (!logoError && logoFiles && logoFiles.length > 0) {
      console.log('  Arquivos encontrados:');
      logoFiles.forEach(file => {
        if (file.name) {
          console.log(`    - ${file.name} (${(file.metadata?.size || 0 / 1024).toFixed(1)}KB)`);
        }
      });
    } else {
      console.log('  ⚠️  Bucket vazio ou erro:', logoError?.message || 'sem arquivos');
    }

    // Verificar bucket images para comparação
    console.log('\n🖼️  Verificando bucket "images" (para comparação):');
    const { data: imageFiles, error: imageError } = await supabase.storage
      .from('images')
      .list('', { limit: 5, sortBy: { column: 'created_at', order: 'desc' } });

    if (!imageError && imageFiles && imageFiles.length > 0) {
      console.log('  Últimos arquivos:');
      imageFiles.forEach((file, index) => {
        if (file.name && index < 3) {
          console.log(`    - ${file.name}`);
        }
      });
    }

  } catch (error) {
    console.error('❌ Erro geral:', error);
  }
}

checkBuckets();

check-supabase-storage.ts.content:
/**
 * Script para verificar o status do storage do Supabase
 * Testa se as imagens existem no bucket e verifica as permissões
 */

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.SUPABASE_URL || '';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';

if (!supabaseUrl || !supabaseAnonKey) {
  console.error('SUPABASE_URL e SUPABASE_ANON_KEY devem estar configurados');
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseAnonKey);

async function checkSupabaseStorage() {
  console.log('Verificando conexão com Supabase Storage...');
  console.log('URL:', supabaseUrl);
  console.log('Key exists:', Boolean(supabaseAnonKey));

  try {
    // 1. Verificar se podemos listar buckets
    console.log('\n1. Listando buckets...');
    const { data: buckets, error: bucketsError } = await supabase.storage.listBuckets();

    if (bucketsError) {
      console.error('Erro ao listar buckets:', bucketsError);
      return;
    }

    console.log('Buckets encontrados:', buckets?.map(b => b.name));

    // 2. Verificar o bucket de imagens
    console.log('\n2. Verificando bucket "images"...');
    const imagesBucket = buckets?.find(b => b.name === 'images');

    if (!imagesBucket) {
      console.error('Bucket "images" não encontrado');
      return;
    }

    console.log('Bucket "images" encontrado:', imagesBucket);

    // 3. Listar arquivos no bucket
    console.log('\n3. Listando arquivos no bucket "images"...');
    const { data: files, error: filesError } = await supabase.storage
      .from('images')
      .list('', { limit: 10 });

    if (filesError) {
      console.error('Erro ao listar arquivos:', filesError);
      return;
    }

    console.log(`Encontrados ${files?.length || 0} arquivos no bucket`);
    files?.forEach((file, index) => {
      console.log(`  ${index + 1}. ${file.name} (${file.metadata?.size || 'unknown size'})`);
    });

    // 4. Testar acesso público a um arquivo específico
    if (files && files.length > 0) {
      console.log('\n4. Testando acesso público ao primeiro arquivo...');
      const firstFile = files[0];
      const { data: publicUrl } = supabase.storage
        .from('images')
        .getPublicUrl(firstFile.name);

      console.log('URL pública gerada:', publicUrl.publicUrl);

      // Testar se a URL é acessível
      try {
        const response = await fetch(publicUrl.publicUrl);
        console.log('Status da requisição HTTP:', response.status);
        console.log('Headers:', Object.fromEntries(response.headers.entries()));
      } catch (fetchError) {
        console.error('Erro ao fazer requisição HTTP:', fetchError);
      }
    }

    // 5. Verificar arquivos específicos dos posts
    console.log('\n5. Verificando arquivos específicos dos posts...');
    const testFiles = [
      'post_10_1725392776012.webp',
      'post_11_1725392836789.webp',
      'post_23_1725393756456.webp'
    ];

    for (const filename of testFiles) {
      const { data: fileData, error: fileError } = await supabase.storage
        .from('images')
        .download(filename);

      if (fileError) {
        console.log(`❌ ${filename}: ${fileError.message}`);
      } else {
        console.log(`✅ ${filename}: arquivo existe (${fileData?.size || 'unknown'} bytes)`);
      }
    }

  } catch (error) {
    console.error('Erro geral:', error);
  }
}

checkSupabaseStorage().catch(console.error);

clean-duplicate-materials.ts.content:
/**
 * Script para limpar materiais duplicados das aulas
 * 
 * Para executar: npx tsx clean-duplicate-materials.ts
 */

import { Pool, neonConfig } from '@neondatabase/serverless';
import ws from "ws";

neonConfig.webSocketConstructor = ws;

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function cleanDuplicateMaterials() {
  try {
    console.log('🧹 Limpando materiais duplicados...');

    // Buscar aulas com materiais extras
    const lessonsQuery = `
      SELECT id, title, extra_materials 
      FROM lessons 
      WHERE extra_materials IS NOT NULL AND extra_materials != '[]'
    `;

    const result = await pool.query(lessonsQuery);

    for (const lesson of result.rows) {
      console.log(`\n📚 Aula ${lesson.id}: ${lesson.title}`);

      let materials = lesson.extra_materials;
      if (typeof materials === 'string') {
        try {
          materials = JSON.parse(materials);
        } catch (e) {
          console.warn('  ⚠️ Erro ao fazer parse dos materiais');
          continue;
        }
      }

      if (Array.isArray(materials) && materials.length > 0) {
        console.log(`  📄 Materiais encontrados: ${materials.length}`);

        // Corrigir nomes com encoding e remover duplicados
        const cleanedMaterials = materials.map(material => ({
          ...material,
          name: material.name.replace(/Ã§Ã£o/g, 'ção').replace(/Ã£/g, 'ã').replace(/Ã§/g, 'ç')
        }));

        // Remover duplicados baseado no nome do arquivo (após correção)
        const uniqueMaterials = cleanedMaterials.filter((material, index, self) => 
          index === self.findIndex(m => m.name === material.name)
        );

        if (uniqueMaterials.length !== materials.length) {
          console.log(`  🔧 Removendo ${materials.length - uniqueMaterials.length} duplicados`);

          // Atualizar no banco
          const updateQuery = `
            UPDATE lessons 
            SET extra_materials = $1 
            WHERE id = $2
          `;

          await pool.query(updateQuery, [JSON.stringify(uniqueMaterials), lesson.id]);
          console.log(`  ✅ Aula ${lesson.id} atualizada`);
        } else {
          console.log(`  ✅ Nenhum duplicado encontrado`);
        }

        // Mostrar materiais finais
        console.log('  📋 Materiais únicos:');
        uniqueMaterials.forEach((material, index) => {
          console.log(`    ${index + 1}. ${material.name}`);
        });
      }
    }

    console.log('\n🎉 Limpeza concluída!');

  } catch (error) {
    console.error('❌ Erro durante a limpeza:', error);
  } finally {
    await pool.end();
  }
}

cleanDuplicateMaterials();

clear-posts-data.ts.content:
/**
 * Script para limpar todos os posts do banco de dados
 * Mantém usuários, categorias e outras tabelas intactas
 * Reseta a sequência de IDs para começar do 1 novamente
 */

import { Pool } from '@neondatabase/serverless';

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function clearPostsData() {
  try {
    console.log('Iniciando limpeza dos dados de posts...');

    // 1. Verificar quantos posts existem atualmente
    const countResult = await pool.query('SELECT COUNT(*) as total FROM posts');
    console.log(`Encontrados ${countResult.rows[0].total} posts para remover`);

    // 2. Limpar todos os posts
    await pool.query('DELETE FROM posts');
    console.log('✅ Todos os posts foram removidos');

    // 3. Resetar a sequência de ID para começar do 1
    await pool.query('ALTER SEQUENCE posts_id_seq RESTART WITH 1');
    console.log('✅ Sequência de IDs resetada para começar do 1');

    // 4. Verificar se a limpeza foi bem-sucedida
    const finalCount = await pool.query('SELECT COUNT(*) as total FROM posts');
    console.log(`Posts restantes: ${finalCount.rows[0].total}`);

    // 5. Verificar se outras tabelas estão intactas
    const usersCount = await pool.query('SELECT COUNT(*) as total FROM users');
    const categoriesCount = await pool.query('SELECT COUNT(*) as total FROM categories');

    console.log('\n📊 Status das outras tabelas:');
    console.log(`- Usuários: ${usersCount.rows[0].total}`);
    console.log(`- Categorias: ${categoriesCount.rows[0].total}`);

    console.log('\n🎉 Banco de dados limpo e pronto para novos uploads!');
    console.log('Agora você pode fazer o upload das imagens novamente.');

  } catch (error) {
    console.error('Erro ao limpar dados dos posts:', error);
  } finally {
    await pool.end();
  }
}

clearPostsData();

create-admin-user.ts.content:
import { db } from "./server/db";
import { users } from "./shared/schema";
import { scrypt, randomBytes } from "crypto";
import { promisify } from "util";
import { eq, or } from "drizzle-orm";

const scryptAsync = promisify(scrypt);

async function hashPassword(password: string) {
  const salt = randomBytes(16).toString("hex");
  const buf = (await scryptAsync(password, salt, 64)) as Buffer;
  return `${buf.toString("hex")}.${salt}`;
}

async function createAdminUser() {
  try {
    // Verificar se o usuário admin já existe
    const [existingAdmin] = await db
      .select()
      .from(users)
      .where(
        or(
          eq(users.email, "admin@example.com"),
          eq(users.username, "testadmin")
        )
      );

    if (existingAdmin) {
      console.log("Um usuário admin já existe:", existingAdmin);

      // Atualize a senha do usuário existente
      const hashedPassword = await hashPassword("password123");
      await db
        .update(users)
        .set({ 
          password: hashedPassword 
        })
        .where(eq(users.id, existingAdmin.id));

      console.log("Senha do admin atualizada com sucesso");
    } else {
      // Criar novo usuário admin
      const hashedPassword = await hashPassword("password123");
      const [admin] = await db
        .insert(users)
        .values({
          username: "testadmin",
          email: "admin@example.com",
          password: hashedPassword,
          is_admin: true,
          created_at: new Date(),
        })
        .returning();

      console.log("Novo admin criado:", admin);
    }

    // Verificar usuário atual jean.maringa@hotmail.com
    const [jeanUser] = await db
      .select()
      .from(users)
      .where(eq(users.email, "jean.maringa@hotmail.com"));

    if (jeanUser) {
      const hashedPassword = await hashPassword("admin123");
      await db
        .update(users)
        .set({ password: hashedPassword })
        .where(eq(users.id, jeanUser.id));

      console.log("Senha do usuário jean.maringa@hotmail.com atualizada");
    }

    console.log("Processo concluído com sucesso!");
  } catch (error) {
    console.error("Erro ao criar/atualizar usuário admin:", error);
  } finally {
    process.exit(0);
  }
}

createAdminUser();

create-categories-tables.ts.content:
/**
 * Script para sincronizar as categorias entre o PostgreSQL direto e o Supabase
 * 
 * Este script realizará as seguintes tarefas:
 * 1. Verificar quais categorias existem no Supabase
 * 2. Criar essas categorias no PostgreSQL direto se não existirem
 * 
 * Para executar:
 * npx tsx create-categories-tables.ts
 */

import { createClient } from '@supabase/supabase-js';
import { Pool } from '@neondatabase/serverless';
import 'dotenv/config';

// Valores fixos para garantir funcionamento
const supabaseUrl = 'https://kmunxjuiuxaqitbovjls.supabase.co';
const supabaseKey = process.env.VITE_SUPABASE_KEY || process.env.SUPABASE_KEY || '';
const databaseUrl = process.env.DATABASE_URL || '';

// Verificar se temos as variáveis de ambiente necessárias
if (!supabaseKey || !databaseUrl) {
  console.error('Erro: Variáveis de ambiente SUPABASE_KEY e DATABASE_URL são necessárias.');
  process.exit(1);
}

console.log(`Usando Supabase URL: ${supabaseUrl}`);
console.log(`Database URL presente: ${!!databaseUrl}`);

// Criar cliente do Supabase
const supabase = createClient(supabaseUrl, supabaseKey);

// Criar conexão com o PostgreSQL
const pool = new Pool({ connectionString: databaseUrl });

/**
 * Função principal para sincronizar as categorias
 */
async function syncCategories() {
  try {
    console.log('Iniciando sincronização de categorias entre Supabase e PostgreSQL direto...');

    // 1. Buscar categorias do Supabase
    const { data: supabaseCategories, error: supabaseError } = await supabase
      .from('categories')
      .select('*');

    if (supabaseError) {
      throw new Error(`Erro ao buscar categorias do Supabase: ${supabaseError.message}`);
    }

    console.log(`Encontradas ${supabaseCategories?.length || 0} categorias no Supabase:`);
    console.table(supabaseCategories);

    if (!supabaseCategories || supabaseCategories.length === 0) {
      console.log('Nenhuma categoria encontrada no Supabase para sincronizar.');
      return;
    }

    // 2. Verificar quais categorias existem no PostgreSQL direto
    const pgCategoriesResult = await pool.query('SELECT id, name FROM categories');
    const pgCategories = pgCategoriesResult.rows;

    console.log(`Encontradas ${pgCategories.length} categorias no PostgreSQL direto:`);
    console.table(pgCategories);

    // 3. Identificar categorias que precisam ser criadas no PostgreSQL
    const categoriesToCreate = supabaseCategories.filter(supabaseCat => 
      !pgCategories.some(pgCat => pgCat.id === supabaseCat.id)
    );

    console.log(`Categorias para criar no PostgreSQL: ${categoriesToCreate.length}`);

    // 4. Criar as categorias faltantes no PostgreSQL
    if (categoriesToCreate.length > 0) {
      console.log('Criando categorias no PostgreSQL...');

      for (const category of categoriesToCreate) {
        try {
          // Criar tabela de categorias se não existir
          await pool.query(`
            CREATE TABLE IF NOT EXISTS categories (
              id SERIAL PRIMARY KEY,
              name TEXT NOT NULL,
              slug TEXT,
              description TEXT,
              image_url TEXT,
              is_active BOOLEAN DEFAULT true,
              created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
            )
          `);

          // Inserir categoria com o mesmo ID do Supabase
          const insertResult = await pool.query(`
            INSERT INTO categories (id, name, slug, description, image_url, is_active, created_at)
            VALUES ($1, $2, $3, $4, $5, $6, $7)
            ON CONFLICT (id) DO UPDATE
            SET name = $2, slug = $3, description = $4, image_url = $5, is_active = $6
            RETURNING id, name
          `, [
            category.id,
            category.name,
            category.slug || '',
            category.description || '',
            category.image_url || null,
            category.is_active !== false, // Se for null ou undefined, assume true
            category.created_at || new Date()
          ]);

          console.log(`Categoria criada/atualizada: ${insertResult.rows[0].name} (ID: ${insertResult.rows[0].id})`);
        } catch (insertError) {
          console.error(`Erro ao criar categoria ${category.name} (ID: ${category.id}):`, insertError);
        }
      }

      console.log('Sincronização de categorias concluída!');
    } else {
      console.log('Todas as categorias já estão sincronizadas entre Supabase e PostgreSQL direto.');
    }

  } catch (error) {
    console.error('Erro durante a sincronização de categorias:', error);
  } finally {
    // Fechar conexão com o banco de dados
    await pool.end();
  }
}

// Executar a função principal
syncCategories().catch(error => {
  console.error('Erro na execução do script:', error);
  process.exit(1);
});

create-course-tables.ts.content:
/**
 * Script para criar as tabelas de cursos no banco de dados
 * 
 * Para executar: npx tsx create-course-tables.ts
 */

import { Pool } from '@neondatabase/serverless';
import dotenv from 'dotenv';

dotenv.config();

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function createCourseTables() {
  try {
    console.log('Criando tabelas de cursos...');

    // Criar enum para tipos de aula
    await pool.query(`
      CREATE TYPE lesson_type AS ENUM ('video', 'pdf', 'link', 'text');
    `);
