create-delete-policy-direct.ts.content:
/**
 * Script para criar diretamente uma política de exclusão (DELETE) para a tabela categorias no Supabase
 * Utilizando apenas consultas SQL simples via API REST do Supabase
 * 
 * Para executar:
 * npx tsx create-delete-policy-direct.ts
 */

import { createClient } from '@supabase/supabase-js';
import dotenv from 'dotenv';

dotenv.config();

// Obtendo a URL e chave do Supabase das variáveis de ambiente
const supabaseUrl = process.env.SUPABASE_URL;
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !supabaseKey) {
  console.error('Erro: SUPABASE_URL e SUPABASE_SERVICE_ROLE_KEY devem estar definidos nas variáveis de ambiente');
  process.exit(1);
}

console.log('URL do Supabase:', supabaseUrl);
console.log('Chave do Supabase válida:', supabaseKey.length > 0);

// Criando o cliente Supabase com a chave de serviço (role key) que tem permissões de admin
const supabase = createClient(supabaseUrl, supabaseKey);

/**
 * Executa uma consulta SQL direto no Supabase
 */
async function executeSql(sql: string, params: any[] = []): Promise<any> {
  try {
    const { data, error } = await supabase.rpc('pgaudit_exec_sql', { cmd: sql, params });

    if (error) throw error;

    return data;
  } catch (error: any) {
    // Se a função pgaudit_exec_sql não existir, tentamos usar a função execute_sql
    try {
      const { data, error: execError } = await supabase.rpc('execute_sql', { sql });

      if (execError) throw execError;

      return data;
    } catch (execError: any) {
      // Se ambas falharem, tentamos fazer uma solicitação REST direta
      console.error('Erro ao executar SQL via funções RPC:', execError.message);

      // Como uma alternativa, vamos tentar uma consulta na tabela pg_policies
      if (sql.toLowerCase().includes('select')) {
        if (sql.toLowerCase().includes('pg_policies')) {
          const { data, error: queryError } = await supabase
            .from('pg_policies')
            .select('*');

          if (queryError) throw queryError;

          return data;
        }
      }

      throw new Error(`Não foi possível executar a consulta SQL: ${execError.message}`);
    }
  }
}

/**
 * Verifica se a policy já existe
 */
async function checkIfPolicyExists(): Promise<boolean> {
  try {
    // Tentando verificar diretamente via pg_policies
    const { data, error } = await supabase
      .from('pg_policies')
      .select('*')
      .eq('tablename', 'categorias')
      .eq('cmd', 'DELETE');

    if (error) {
      console.error('Erro ao verificar policies:', error);
      // Se não conseguimos acessar pg_policies, vamos assumir que não existe
      return false;
    }

    return data && data.length > 0;
  } catch (error) {
    console.error('Erro ao verificar se a policy existe:', error);
    return false;
  }
}

/**
 * Cria a política de DELETE para categorias usando SQL direto
 */
async function createDeletePolicy() {
  try {
    // Verificamos primeiro se a policy já existe
    const policyExists = await checkIfPolicyExists();

    if (policyExists) {
      console.log('A política de DELETE para categorias já existe');
      return;
    }

    // Criar a política de DELETE para categorias
    console.log('Criando política de DELETE para categorias...');

    // Como não conseguimos verificar corretamente, vamos tentar criar diretamente
    // e tratar erros de "já existe" como sucesso
    try {
      const sql = `
        alter table public.categorias
        enable row level security;
      `;

      await executeSql(sql);
      console.log('RLS ativado para a tabela categorias');
    } catch (error: any) {
      if (error.message.includes('already')) {
        console.log('RLS já estava ativado para a tabela categorias');
      } else {
        throw error;
      }
    }

    try {
      const sql = `
        create policy "Permitir exclusão de categorias"
        on public.categorias
        for delete
        to authenticated
        using (true);
      `;

      await executeSql(sql);
      console.log('Política de DELETE adicionada com sucesso!');
    } catch (error: any) {
      if (error.message.includes('already exists')) {
        console.log('Política já existia');
      } else {
        throw error;
      }
    }

    // Alterar chave estrangeira para ON DELETE SET NULL
    try {
      console.log('Verificando se é necessário alterar a chave estrangeira entre posts e categorias...');

      // Primeiro, verificamos o nome da constraint
      const constraintSql = `
        SELECT 
          tc.constraint_name 
        FROM 
          information_schema.table_constraints tc
          JOIN information_schema.constraint_column_usage ccu ON tc.constraint_name = ccu.constraint_name
        WHERE 
          tc.constraint_type = 'FOREIGN KEY' 
          AND tc.table_name = 'posts' 
          AND ccu.table_name = 'categorias';
      `;

      const constraintData = await executeSql(constraintSql);

      if (constraintData && constraintData.length > 0) {
        const constraintName = constraintData[0].constraint_name;

        console.log(`Constraint encontrada: ${constraintName}`);
        console.log('Alterando para ON DELETE SET NULL...');

        const alterSql = `
          ALTER TABLE public.posts 
          DROP CONSTRAINT ${constraintName},
          ADD CONSTRAINT ${constraintName} 
          FOREIGN KEY (category_id) 
          REFERENCES public.categorias(id)
          ON DELETE SET NULL;
        `;

        await executeSql(alterSql);
        console.log('Chave estrangeira alterada com sucesso para ON DELETE SET NULL!');
      } else {
        console.log('Não foi possível encontrar a constraint ou ela não existe');
      }
    } catch (error: any) {
      console.error('Erro ao alterar a chave estrangeira:', error.message);
    }

    console.log('Processo concluído com sucesso!');

  } catch (error: any) {
    console.error('Erro ao criar policy:', error.message);
  }
}

// Função principal para executar o script
async function main() {
  try {
    console.log('Iniciando criação de política DELETE para categorias no Supabase...');
    await createDeletePolicy();
  } catch (error: any) {
    console.error('Erro geral:', error.message);
  }
}

// Executar a função principal
main();

create-delete-policy-postgres.ts.content:
/**
 * Script para criar uma política de exclusão (DELETE) para a tabela categorias
 * usando conexão direta com o PostgreSQL
 * 
 * Para executar:
 * npx tsx create-delete-policy-postgres.ts
 */

import { Pool } from '@neondatabase/serverless';
import dotenv from 'dotenv';

dotenv.config();

// Obtendo a URL de conexão do banco de dados das variáveis de ambiente
const databaseUrl = process.env.DATABASE_URL;

if (!databaseUrl) {
  console.error('Erro: DATABASE_URL deve estar definida nas variáveis de ambiente');
  process.exit(1);
}

console.log('URL do banco de dados disponível');

// Criando o pool de conexão com o PostgreSQL
const pool = new Pool({ connectionString: databaseUrl });

/**
 * Executa uma consulta SQL diretamente no PostgreSQL
 */
async function executeSql(query: string, params: any[] = []): Promise<any> {
  const client = await pool.connect();
  try {
    const result = await client.query(query, params);
    return result.rows;
  } finally {
    client.release();
  }
}

/**
 * Verifica se a política já existe
 */
async function checkIfPolicyExists(): Promise<boolean> {
  try {
    const query = `
      SELECT *
      FROM pg_policies
      WHERE tablename = 'categorias'
        AND cmd = 'DELETE';
    `;

    const result = await executeSql(query);
    return result && result.length > 0;
  } catch (error) {
    console.error('Erro ao verificar se a policy existe:', error);
    return false;
  }
}

/**
 * Verifica a configuração atual da chave estrangeira
 */
async function checkForeignKeyConfig(): Promise<string | null> {
  try {
    const query = `
      SELECT rc.delete_rule, tc.constraint_name
      FROM information_schema.table_constraints tc
      JOIN information_schema.constraint_column_usage ccu 
        ON ccu.constraint_name = tc.constraint_name
      JOIN information_schema.referential_constraints rc
        ON rc.constraint_name = tc.constraint_name
      WHERE tc.constraint_type = 'FOREIGN KEY'
        AND tc.table_name = 'posts'
        AND ccu.table_name = 'categorias';
    `;

    const result = await executeSql(query);

    if (result && result.length > 0) {
      return result[0];
    }

    return null;
  } catch (error) {
    console.error('Erro ao verificar a configuração da chave estrangeira:', error);
    return null;
  }
}

/**
 * Cria a política de DELETE para categorias
 */
async function createDeletePolicy() {
  try {
    // Verificar se o RLS está ativado
    const rlsQuery = `
      SELECT relrowsecurity
      FROM pg_class
      WHERE oid = 'public.categorias'::regclass;
    `;

    let rlsEnabled = false;
    try {
      const rlsResult = await executeSql(rlsQuery);
      rlsEnabled = rlsResult && rlsResult.length > 0 && rlsResult[0].relrowsecurity;
    } catch (error) {
      console.warn('Não foi possível verificar o status do RLS:', error);
    }

    console.log(`RLS está ${rlsEnabled ? 'ativado' : 'desativado'} para a tabela categorias`);

    // Ativar RLS se necessário
    if (!rlsEnabled) {
      console.log('Ativando RLS para a tabela categorias...');
      try {
        await executeSql(`
          ALTER TABLE public.categorias
          ENABLE ROW LEVEL SECURITY;
        `);
        console.log('RLS ativado com sucesso');
      } catch (error) {
        console.error('Erro ao ativar RLS:', error);
      }
    }

    // Verificar se a política já existe
    const policyExists = await checkIfPolicyExists();

    if (policyExists) {
      console.log('A política de DELETE para categorias já existe');
    } else {
      console.log('Criando política de DELETE para categorias...');

      try {
        await executeSql(`
          CREATE POLICY "Permitir exclusão de categorias"
          ON public.categorias
          FOR DELETE
          TO authenticated
          USING (true);
        `);
        console.log('Política de DELETE criada com sucesso');
      } catch (error: any) {
        if (error.message?.includes('already exists')) {
          console.log('Política já existia');
        } else {
          console.error('Erro ao criar a política:', error);
        }
      }
    }

    // Verificar a configuração da chave estrangeira
    const fkConfig = await checkForeignKeyConfig();

    if (fkConfig) {
      console.log(`Configuração atual da chave estrangeira: ${fkConfig.constraint_name}, DELETE RULE: ${fkConfig.delete_rule}`);

      if (fkConfig.delete_rule === 'RESTRICT' || fkConfig.delete_rule === 'NO ACTION') {
        console.log('Alterando a configuração da chave estrangeira para ON DELETE SET NULL...');

        try {
          await executeSql(`
            ALTER TABLE public.posts
            DROP CONSTRAINT ${fkConfig.constraint_name},
            ADD CONSTRAINT ${fkConfig.constraint_name}
            FOREIGN KEY (category_id)
            REFERENCES public.categorias(id)
            ON DELETE SET NULL;
          `);
          console.log('Chave estrangeira alterada com sucesso para ON DELETE SET NULL');
        } catch (error) {
          console.error('Erro ao alterar a chave estrangeira:', error);
        }
      } else if (fkConfig.delete_rule === 'SET NULL') {
        console.log('A chave estrangeira já está configurada com ON DELETE SET NULL');
      } else {
        console.log(`A chave estrangeira tem uma regra de exclusão diferente: ${fkConfig.delete_rule}`);
      }
    } else {
      console.log('Nenhuma chave estrangeira encontrada entre posts e categorias');
    }

  } catch (error) {
    console.error('Erro ao criar política ou configurar chave estrangeira:', error);
    throw error;
  }
}

/**
 * Função principal que executa o script
 */
async function main() {
  try {
    console.log('Iniciando configuração de política DELETE para categorias...');
    await createDeletePolicy();
    console.log('Configuração concluída com sucesso');
  } catch (error) {
    console.error('Erro geral:', error);
  } finally {
    // Fechar o pool de conexões
    await pool.end();
  }
}

// Executar a função principal
main();

