        ('Figma', 'Ferramenta de design colaborativo', 'https://figma.com', ${designCategory[0].id}, false),
        ('Adobe Photoshop', 'Editor de imagens profissional', 'https://adobe.com/photoshop', ${designCategory[0].id}, false)
