/**
 * Script para adicionar a coluna group_id na tabela posts do Supabase
 */

import { supabase } from './server/supabase-client';

async function addGroupIdColumn() {
  try {
    console.log('Adicionando coluna group_id na tabela posts do Supabase...');

    // Executar SQL para adicionar a coluna group_id se não existir
    const { data, error } = await supabase.rpc('exec_sql', {
      sql: `
        DO $$ 
        BEGIN
          IF NOT EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_name = 'posts' AND column_name = 'group_id'
          ) THEN
            ALTER TABLE posts ADD COLUMN group_id TEXT;
            PRINT 'Coluna group_id adicionada com sucesso';
          ELSE
            PRINT 'Coluna group_id já existe';
          END IF;
        END $$;
      `
    });

    if (error) {
      console.error('Erro ao executar SQL:', error);

      // Tentar método alternativo
      console.log('Tentando método alternativo...');
      const { error: altError } = await supabase
        .from('posts')
        .select('group_id')
        .limit(1);

      if (altError && altError.code === '42703') {
        console.log('A coluna group_id realmente não existe no Supabase. Será necessário adicionar manualmente no painel.');
        console.log('Execute este SQL no SQL Editor do Supabase:');
        console.log('ALTER TABLE posts ADD COLUMN group_id TEXT;');
      }
    } else {
      console.log('Comando executado com sucesso:', data);
    }

  } catch (error) {
    console.error('Erro:', error);
  }
}

addGroupIdColumn();

fix-unique-codes.ts.content:
/**
 * Script para corrigir posts sem unique_code no Supabase
 */

import { createClient } from '@supabase/supabase-js';

// Limpar aspas extras das variáveis de ambiente
const supabaseUrl = process.env.VITE_SUPABASE_URL?.replace(/"/g, '') || '';
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY?.replace(/"/g, '') || '';

console.log('URL do Supabase:', supabaseUrl);

const supabase = createClient(supabaseUrl, supabaseKey);

async function generateUniqueCode(id: number): Promise<string> {
  return `${id}-${Date.now().toString(36)}`;
}

async function fixUniqueCodesInSupabase() {
  try {
    console.log('Buscando posts sem unique_code no Supabase...');

    // Buscar posts com unique_code NULL
    const { data: postsWithoutCode, error: fetchError } = await supabase
      .from('posts')
      .select('id, title, unique_code')
      .is('unique_code', null);

    if (fetchError) {
      console.error('Erro ao buscar posts:', fetchError);
      return;
    }

    if (!postsWithoutCode || postsWithoutCode.length === 0) {
      console.log('Todos os posts já têm unique_code!');
      return;
    }

    console.log(`Encontrados ${postsWithoutCode.length} posts sem unique_code`);

    // Atualizar cada post
    for (const post of postsWithoutCode) {
      const newUniqueCode = await generateUniqueCode(post.id);

      console.log(`Atualizando post ${post.id}: "${post.title}" com unique_code: ${newUniqueCode}`);

      const { error: updateError } = await supabase
        .from('posts')
        .update({ unique_code: newUniqueCode })
        .eq('id', post.id);

      if (updateError) {
        console.error(`Erro ao atualizar post ${post.id}:`, updateError);
      } else {
        console.log(`✓ Post ${post.id} atualizado com sucesso`);
      }
    }

    console.log('Processo concluído!');

  } catch (error) {
    console.error('Erro no processo:', error);
  }
}

fixUniqueCodesInSupabase();

