      event: 'UNKNOWN_EVENT',
      data: {}
    };

    const response3 = await fetch(WEBHOOK_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(unknownPayload)
    });

    const result3 = await response3.json();
    console.log(`Status: ${response3.status}`);
    console.log('Resposta:', result3);
