/**
 * Script para atualizar URLs das imagens no banco para o caminho correto do Supabase Storage
 * Corrige os caminhos para apontar para images/uploads/ onde as imagens estão realmente armazenadas
 */

import { Pool } from '@neondatabase/serverless';

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function updateImageUrls() {
  try {
    console.log('Atualizando URLs das imagens para o caminho correto...');

    // Buscar todos os posts com URLs do Supabase que não incluem 'uploads/'
    const result = await pool.query(`
      SELECT id, title, image_url 
      FROM posts 
      WHERE image_url LIKE '%supabase.co%' 
      AND image_url NOT LIKE '%uploads/%'
    `);

    console.log(`Encontrados ${result.rows.length} posts com URLs para corrigir`);

    let updatedCount = 0;

    for (const post of result.rows) {
      // Extrair o nome do arquivo da URL atual
      const filename = post.image_url.split('/').pop()?.split('?')[0];

      if (filename) {
        // Construir a URL correta apontando para images/uploads/
        const baseUrl = post.image_url.split('/storage/v1/object/public/images/')[0];
        const correctUrl = `${baseUrl}/storage/v1/object/public/images/uploads/${filename}`;

        console.log(`Post #${post.id}: ${post.title}`);
        console.log(`  De: ${post.image_url}`);
        console.log(`  Para: ${correctUrl}`);

        // Atualizar no banco
        await pool.query(`
          UPDATE posts 
          SET image_url = $1 
          WHERE id = $2
        `, [correctUrl, post.id]);

        updatedCount++;
      }
    }

    console.log(`\n✅ ${updatedCount} URLs de imagens foram atualizadas com sucesso!`);

    // Verificar alguns resultados
    const checkResult = await pool.query(`
      SELECT id, title, image_url 
      FROM posts 
      WHERE image_url LIKE '%uploads/%'
      ORDER BY id 
      LIMIT 5
    `);

    console.log('\nPrimeiros 5 posts com URLs corrigidas:');
    checkResult.rows.forEach(post => {
      console.log(`#${post.id}: ${post.title} -> ${post.image_url}`);
    });

  } catch (error) {
    console.error('Erro ao atualizar URLs das imagens:', error);
  } finally {
    await pool.end();
  }
}

updateImageUrls();

update-post-premium.ts.content:
/**
 * Script para atualizar todos os posts no Supabase
 * Garante que todos os posts tenham os campos licenseType e isPro corretamente preenchidos
 * 
 * Para executar:
 * ts-node update-post-premium.ts
 */

import { createClient } from '@supabase/supabase-js';
import 'dotenv/config';

// Verificar se as variáveis de ambiente necessárias estão definidas
const supabaseUrl = process.env.SUPABASE_URL;
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !supabaseKey) {
  console.error('Erro: SUPABASE_URL e SUPABASE_SERVICE_ROLE_KEY devem estar definidos no ambiente.');
  process.exit(1);
}

// Criar cliente Supabase com a chave de serviço para ter acesso total
const supabase = createClient(supabaseUrl, supabaseKey);

async function updateAllPosts() {
  console.log('Iniciando atualização de posts...');

  try {
    // 1. Buscar todos os posts
    const { data: posts, error } = await supabase
      .from('posts')
      .select('*');

    if (error) {
      throw error;
    }

    if (!posts || posts.length === 0) {
      console.log('Nenhum post encontrado para atualizar.');
      return;
    }

    console.log(`Encontrados ${posts.length} posts para atualizar.`);

    // 2. Iterar por cada post e atualizar seus campos
    let successCount = 0;
    let errorCount = 0;

    for (const post of posts) {
      // Define default premium status based on naming convention
      // Se o título ou descrição contiver "premium", consideramos como premium
      const isPremiumByTitle = 
        (post.title && post.title.toLowerCase().includes('premium')) || 
        (post.description && post.description.toLowerCase().includes('premium'));

      // Determina se deveria ser premium baseado nas informações existentes
      const shouldBePremium = post.is_pro === true || 
                             post.license_type === 'premium' || 
                             isPremiumByTitle;

      try {
        // Atualiza ambos os campos para garantir consistência
        const { error: updateError } = await supabase
          .from('posts')
          .update({
            is_pro: shouldBePremium,
            license_type: shouldBePremium ? 'premium' : 'free'
          })
          .eq('id', post.id);

        if (updateError) {
          throw updateError;
        }

        console.log(`✓ Post #${post.id} atualizado: ${shouldBePremium ? 'PREMIUM' : 'FREE'}`);
        successCount++;
      } catch (updateError) {
        console.error(`✗ Erro ao atualizar post #${post.id}:`, updateError);
        errorCount++;
      }
    }

    console.log('\nResumo da operação:');
    console.log(`- Total de posts: ${posts.length}`);
    console.log(`- Atualizados com sucesso: ${successCount}`);
    console.log(`- Falhas: ${errorCount}`);

  } catch (error) {
    console.error('Erro ao processar os posts:', error);
  }
}

// Executar o script
updateAllPosts()
  .then(() => {
    console.log('Script concluído.');
    process.exit(0);
  })
  .catch((error) => {
    console.error('Erro durante a execução do script:', error);
    process.exit(1);
  });

