          paramIndex++;
        }
      }

      if (isAdmin !== undefined) {
        setClauses.push(`is_admin = $${paramIndex}`);
        queryParams.push(isAdmin);
        paramIndex++;
      }

      if (tipo !== undefined) {
        setClauses.push(`tipo = $${paramIndex}`);
        queryParams.push(tipo);
        paramIndex++;
      }

      if (plano_id !== undefined) {
