/**
 * Este arquivo centraliza a instância do Supabase client para o servidor
 * Reutiliza a mesma lógica do cliente, mas pode ser configurado de forma independente
 */

import { createClient } from '@supabase/supabase-js';

function isValidUrl(urlString: string): boolean {
  try {
    new URL(urlString);
    return true;
  } catch (error) {
    return false;
  }
}

function createSupabaseClient() {
  let supabaseUrl = process.env.SUPABASE_URL || '';
  const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_KEY || '';
  const projectRef = process.env.SUPABASE_PROJECT_REF || '';

  // If we have a project reference but no full URL, construct the URL
  if (projectRef && (!supabaseUrl || !isValidUrl(supabaseUrl))) {
    supabaseUrl = `https://${projectRef}.supabase.co`;
    console.log('Construindo URL do Supabase a partir do project ref:', supabaseUrl);
  }

  // If still no valid URL, try to extract project ref from existing URL-like string
  if (!isValidUrl(supabaseUrl) && supabaseUrl) {
    // Clean the URL string and reconstruct
    const cleanRef = supabaseUrl.replace(/[^a-zA-Z0-9]/g, '');
    if (cleanRef.length > 10) { // Supabase project refs are typically 20+ chars
      supabaseUrl = `https://${cleanRef}.supabase.co`;
      console.log('URL reconstruída:', supabaseUrl);
    }
  }

  if (!supabaseUrl || !supabaseKey) {
    console.error('Credenciais do Supabase não encontradas');
    console.error('SUPABASE_URL:', supabaseUrl);
    console.error('SUPABASE_KEY exists:', Boolean(supabaseKey));
    throw new Error('Credenciais do Supabase não configuradas');
  }

  if (!isValidUrl(supabaseUrl)) {
    console.error('SUPABASE_URL inválida após processamento:', supabaseUrl);
    throw new Error('SUPABASE_URL inválida');
  }

  console.log('Inicializando cliente Supabase do servidor com URL:', supabaseUrl);
  console.log('Chave Supabase válida:', Boolean(supabaseKey));

  return createClient(supabaseUrl, supabaseKey);
}

export const supabase = createSupabaseClient();

/**
 * Verifica se o bucket de imagens existe e o cria se necessário
 */
export async function ensureImageBucket() {
  try {
    const { data: buckets, error } = await supabase.storage.listBuckets();

    if (error) {
      console.error('Erro ao listar buckets:', error);
      return;
    }

    // Contar buckets encontrados para debug
    console.log(`Buckets encontrados: ${buckets.length}`);

    const imagesBucket = buckets.find(bucket => bucket.name === 'images');

    if (!imagesBucket) {
      console.log('Criando bucket de imagens...');

      const { error: createError } = await supabase.storage.createBucket('images', {
        public: true, // Acesso público para leitura
        fileSizeLimit: 10485760 // 10MB
      });

      if (createError) {
        console.error('Erro ao criar bucket de imagens:', createError);
      } else {
        console.log('Bucket de imagens criado com sucesso');

        // Configurar políticas de acesso
        await configureImageBucketPolicies();
      }
    } else {
      console.log('Bucket de imagens já existe');

      // Verificar se as políticas estão configuradas
      await configureImageBucketPolicies();
    }
  } catch (error) {
    console.error('Erro ao verificar/criar bucket de imagens:', error);
  }
}

/**
 * Configura políticas de acesso para o bucket de imagens
 * 
 * Nota: As políticas de acesso geralmente são configuradas no painel do Supabase,
 * não via API. Aqui tentamos garantir que o bucket seja público para leitura,
 * mas as políticas de RLS (Row Level Security) precisam ser configuradas no painel.
 */
async function configureImageBucketPolicies() {
  try {
    // Nome do bucket
    const bucketName = 'images';

    // Atualizar configurações do bucket para permitir acesso público
    const { error: updateError } = await supabase.storage.updateBucket(bucketName, {
      public: true,
      allowedMimeTypes: ['image/jpeg', 'image/png', 'image/webp', 'image/gif', 'image/svg+xml'],
      fileSizeLimit: 10485760 // 10MB
    });

    if (updateError) {
      console.error('Erro ao atualizar bucket para acesso público:', updateError);
    } else {
      console.log('Bucket configurado para acesso público com sucesso');
    }

    // Mensagem de instruções para o console
    console.log(`
=================================================
IMPORTANTE: POLÍTICAS DE ACESSO PARA SUPABASE
=================================================
Para garantir que o upload de imagens funcione corretamente, 
você precisa configurar as políticas de acesso no painel do Supabase:

1. Acesse o painel do Supabase: https://app.supabase.io
2. Vá para "Storage" > "Policies"
3. Para o bucket "images", adicione políticas:
   - Para permitir SELECT para todos: "true"
   - Para permitir INSERT para usuários autenticados: "true"

Sem estas políticas, os uploads podem falhar com erros de permissão.
=================================================
`);

  } catch (error) {
    console.error('Erro ao configurar políticas de bucket:', error);
  }
}

/**
 * Retorna a URL pública de uma imagem armazenada no Supabase
 */
export function getPublicImageUrl(filePath: string) {
  const { data } = supabase.storage.from('images').getPublicUrl(filePath);
  return data.publicUrl;
}

server/supabase-upload.ts.content:
/**
 * Utilitário para upload de imagens no Supabase Storage com conversão WebP
 */

import { createClient } from '@supabase/supabase-js';
import sharp from 'sharp';
import ffmpeg from 'fluent-ffmpeg';
import ffmpegPath from '@ffmpeg-installer/ffmpeg';
import { writeFile, unlink } from 'fs/promises';
import path from 'path';
import os from 'os';

// Configure FFmpeg path
ffmpeg.setFfmpegPath(ffmpegPath.path);

// Configuração do Supabase
const supabaseUrl = process.env.SUPABASE_URL?.replace(/"/g, '');
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY?.replace(/"/g, '');

if (!supabaseUrl || !supabaseKey) {
  throw new Error('Variáveis SUPABASE_URL e SUPABASE_SERVICE_ROLE_KEY são obrigatórias');
}

const supabase = createClient(supabaseUrl, supabaseKey);

/**
 * Comprime e converte imagem para WebP usando Sharp
 */
async function compressAndConvertToWebP(buffer: Buffer, originalName: string): Promise<Buffer> {
  try {
    console.log(`Comprimindo e convertendo ${originalName} para WebP...`);

    // Usar Sharp para comprimir e converter para WebP
    const compressedBuffer = await sharp(buffer)
      .resize(1920, 1920, { 
        fit: 'inside', 
        withoutEnlargement: true 
      })
      .webp({ 
        quality: 85,
        effort: 4
      })
      .toBuffer();

    console.log(`Conversão WebP bem-sucedida: ${originalName} -> ${(compressedBuffer.length / 1024).toFixed(1)}KB`);
    return compressedBuffer;
  } catch (error) {
    console.warn('Falha na compressão WebP, usando original:', error);
    return buffer;
  }
}

/**
 * Converte vídeo/GIF para WebM usando FFmpeg
 */
async function convertToWebM(buffer: Buffer, originalName: string): Promise<Buffer> {
  const tempDir = os.tmpdir();
  const inputPath = path.join(tempDir, `input_${Date.now()}_${originalName}`);
  const outputPath = path.join(tempDir, `output_${Date.now()}.webm`);

  try {
    console.log(`Convertendo ${originalName} para WebM...`);

    // Escrever arquivo temporário
    await writeFile(inputPath, buffer);

    // Converter usando FFmpeg com configurações mais robustas
    await new Promise<void>((resolve, reject) => {
      const command = ffmpeg(inputPath);

      // Detectar se é GIF ou MP4 para ajustar configurações
      const isGif = originalName.toLowerCase().includes('.gif');

      if (isGif) {
        // Para GIFs: configuração mais simples sem áudio
        command
          .videoCodec('libvpx')
          .noAudio() // GIFs não têm áudio
          .size('?x480') // Manter aspecto original, max altura 480
          .fps(12) // FPS mais baixo para GIFs
          .videoBitrate('300k')
          .outputOptions([
            '-f webm',
            '-pix_fmt yuv420p',
            '-auto-alt-ref 0', // Importante para GIFs
            '-lag-in-frames 0',
            '-error-resilient 1'
          ]);
      } else {
        // Para MP4s: configuração mais robusta
        command
          .videoCodec('libvpx')
          .audioCodec('libvorbis')
          .size('?x720') // Manter aspecto, max altura 720
          .fps(20)
          .videoBitrate('500k')
          .audioBitrate('96k')
          .outputOptions([
            '-f webm',
            '-pix_fmt yuv420p',
            '-error-resilient 1'
          ]);
      }

      command
        .output(outputPath)
        .on('start', (commandLine) => {
          console.log(`FFmpeg iniciado: ${commandLine}`);
        })
        .on('progress', (progress) => {
          if (progress.percent) {
            console.log(`Progresso: ${Math.round(progress.percent)}%`);
          }
        })
        .on('end', () => {
          console.log(`Conversão WebM concluída: ${originalName}`);
          resolve();
        })
        .on('error', (error, stdout, stderr) => {
          console.error(`Erro na conversão WebM de ${originalName}:`, {
            error: error.message,
            stdout: stdout,
            stderr: stderr
          });
          reject(error);
        })
        .run();
    });

    // Ler arquivo convertido
    const { readFile } = await import('fs/promises');
    const convertedBuffer = await readFile(outputPath);

    console.log(`Conversão WebM bem-sucedida: ${originalName} -> ${(convertedBuffer.length / 1024).toFixed(1)}KB`);

    // Limpeza dos arquivos temporários
    await Promise.all([
      unlink(inputPath).catch(() => {}),
      unlink(outputPath).catch(() => {})
    ]);

    return convertedBuffer;

  } catch (error) {
    console.error(`Erro na conversão WebM de ${originalName}:`, error);

    // Limpeza em caso de erro
    await Promise.all([
      unlink(inputPath).catch(() => {}),
      unlink(outputPath).catch(() => {})
    ]);

    throw error;
  }
}

/**
 * Detecta se o arquivo é vídeo ou GIF baseado no MIME type
 */
function isVideoOrGif(mimeType: string): boolean {
  return mimeType === 'video/mp4' || mimeType === 'image/gif';
}

/**
 * Detecta se o arquivo é imagem (exceto GIF e vídeos)
 */
function isImage(mimeType: string): boolean {
  return mimeType.startsWith('image/') && mimeType !== 'image/gif' && !mimeType.includes('webm');
}

/**
 * Faz upload de arquivo (imagem, vídeo ou GIF) para o Supabase Storage
 * Imagens são convertidas para WebP, vídeos/GIFs são convertidos para WebM
 */
export async function uploadFileToSupabase(
  buffer: Buffer,
  originalName: string,
  mimeType: string,
  bucket: string,
  fileName: string
): Promise<{ url: string | null; error: string | null }> {
  try {
    let processedBuffer: Buffer;
    let contentType: string;
    let fileExtension: string;
    let finalBucket = bucket; // Bucket pode mudar baseado no tipo
    const timestamp = Date.now();

    // Determinar o tipo de processamento baseado no MIME type
    if (mimeType === 'video/webm') {
      // Para WebM: upload direto sem conversão
      console.log(`Detectado WebM: ${originalName} (${mimeType}) - upload direto`);
      processedBuffer = buffer;
      contentType = 'video/webm';
      fileExtension = '.webm';
      finalBucket = 'videos'; // Usar bucket específico para vídeos
    } else if (isVideoOrGif(mimeType)) {
      // Para GIFs, manter formato original
      if (mimeType === 'image/gif') {
        console.log(`Mantendo GIF original: ${originalName} (${mimeType})`);
        processedBuffer = buffer;
        contentType = 'image/gif';
        fileExtension = '.gif';
      } else {
        // Para MP4, manter formato original - usar bucket específico
        console.log(`Detectado MP4: ${originalName} (${mimeType}) - usando bucket videos`);
        processedBuffer = buffer;
        contentType = 'video/mp4';
        fileExtension = '.mp4';
        finalBucket = 'videos'; // Usar bucket específico para vídeos
      }
    } else if (isImage(mimeType)) {
      // Converter imagem para WebP
      console.log(`Detectado imagem: ${originalName} (${mimeType})`);
      processedBuffer = await compressAndConvertToWebP(buffer, originalName);
      contentType = 'image/webp';
      fileExtension = '.webp';
    } else {
      // Manter formato original para outros tipos
      console.log(`Mantendo formato original: ${originalName} (${mimeType})`);
      processedBuffer = buffer;
      contentType = mimeType;
      fileExtension = path.extname(originalName);
    }

    const finalPath = `${fileName}_${timestamp}${fileExtension}`;

    console.log(`Fazendo upload para Supabase: ${finalBucket}/${finalPath} (${(processedBuffer.length / 1024).toFixed(1)}KB)`);

    // Upload para o Supabase com upsert - usar sempre client normal
    const uploadClient = supabase;

    const { data, error } = await uploadClient.storage
      .from(finalBucket)
      .upload(finalPath, processedBuffer, { 
        contentType, 
        upsert: true 
      });

    if (error) {
      console.error('Erro no upload Supabase:', error);

      // Se é erro de MIME type com WebM, salvar como GIF original
      if (error.message.includes('mime type video/webm is not supported') || 
          error.message.includes('invalid_mime_type')) {
        console.log('Fallback: Salvando arquivo original ao invés do WebM convertido');

        // Upload do arquivo original
        const originalPath = `${fileName}_${timestamp}${path.extname(originalName)}`;
        const { data: fallbackData, error: fallbackError } = await supabase.storage
          .from(bucket)
          .upload(originalPath, buffer, { 
            contentType: mimeType, 
            upsert: true 
          });

        if (fallbackError) {
          console.error('Erro no fallback upload:', fallbackError);
          return { url: null, error: `Upload falhou: ${error.message}` };
        }

        const fallbackUrl = `https://kmunxjuiuxaqitbovjls.supabase.co/storage/v1/object/public/${bucket}/${originalPath}?t=${timestamp}`;
        console.log(`Fallback bem-sucedido (arquivo original): ${fallbackUrl}`);
        return { url: fallbackUrl, error: null };
      }

      return { url: null, error: error.message };
    }

    // Obter URL pública com timestamp para cache-busting
    const publicUrl = `https://kmunxjuiuxaqitbovjls.supabase.co/storage/v1/object/public/${finalBucket}/${finalPath}?t=${timestamp}`;

    console.log(`Upload bem-sucedido: ${publicUrl}`);
    return { url: publicUrl, error: null };

  } catch (error) {
    console.error('Erro geral no upload:', error);
    return { 
      url: null, 
      error: error instanceof Error ? error.message : 'Erro desconhecido no upload' 
    };
  }
}

/**
 * Mantém compatibilidade com a função anterior para upload apenas de imagens
 * @deprecated Use uploadFileToSupabase instead
 */
export async function uploadImageToSupabase(
  buffer: Buffer,
  originalName: string,
  bucket: string,
  fileName: string
): Promise<{ url: string | null; error: string | null }> {
  // Assumir que é imagem se não temos MIME type
  return uploadFileToSupabase(buffer, originalName, 'image/jpeg', bucket, fileName);
}

/**
 * Faz upload especializado para logos (converte SVG para PNG de alta qualidade)
 */
export async function uploadLogoToSupabase(
  buffer: Buffer,
  originalName: string,
  mimeType: string,
  bucket: string,
  fileName: string
): Promise<{ url: string | null; error: string | null }> {
  try {
    let finalBuffer = buffer;
    let contentType = 'image/png';
    let fileExtension = '.png';

    // Gerar timestamp único para evitar cache
    const timestamp = Date.now();

    console.log(`Processando logo: ${originalName} (${mimeType})`);

    // Converter para PNG de alta qualidade (funciona com SVG e outros formatos)
    try {
      if (mimeType === 'image/svg+xml') {
        console.log(`Convertendo SVG ${originalName} para PNG de alta qualidade...`);

        // Para SVG, criar PNG de alta resolução
        finalBuffer = await sharp(buffer, { density: 300 })
          .resize(800, 800, { 
            fit: 'inside', 
            withoutEnlargement: true,
            background: { r: 255, g: 255, b: 255, alpha: 0 } // Fundo transparente
          })
          .png({ 
            quality: 100,
            compressionLevel: 6,
            adaptiveFiltering: true
          })
          .toBuffer();

        console.log(`SVG convertido para PNG de alta qualidade: ${(finalBuffer.length / 1024).toFixed(1)}KB`);
      } else {
        // Para outros formatos, otimizar mantendo boa qualidade
        finalBuffer = await sharp(buffer)
          .resize(800, 800, { 
            fit: 'inside', 
            withoutEnlargement: true 
          })
          .png({ 
            quality: 95,
            compressionLevel: 6
          })
          .toBuffer();

        console.log(`${originalName} otimizado para PNG: ${(finalBuffer.length / 1024).toFixed(1)}KB`);
      }
    } catch (sharpError) {
      console.warn('Falha na conversão, usando original:', sharpError);
      // Se falhar, manter o buffer original
      if (mimeType.startsWith('image/')) {
        contentType = mimeType;
        fileExtension = originalName.includes('.') ? '.' + originalName.split('.').pop() : '';
      }
    }

    const finalPath = `${fileName}_${timestamp}${fileExtension}`;

    console.log(`Fazendo upload do logo: ${bucket}/${finalPath} (${(finalBuffer.length / 1024).toFixed(1)}KB)`);

    // Upload para o Supabase com upsert
    const { data, error } = await supabase.storage
      .from(bucket)
      .upload(finalPath, finalBuffer, { 
        contentType, 
        upsert: true 
      });

    if (error) {
      console.error('Erro no upload do logo:', error);
      return { url: null, error: error.message };
    }

    // Obter URL pública com timestamp para cache-busting
    const publicUrl = `https://kmunxjuiuxaqitbovjls.supabase.co/storage/v1/object/public/${bucket}/${finalPath}?t=${timestamp}`;

    console.log(`Upload do logo bem-sucedido: ${publicUrl}`);
    return { url: publicUrl, error: null };

  } catch (error) {
    console.error('Erro geral no upload do logo:', error);
    return { 
      url: null, 
      error: error instanceof Error ? error.message : 'Erro desconhecido no upload do logo' 
    };
  }
}

/**
 * Assegura que o bucket existe e tem as políticas corretas
 */
export async function ensureBucket(bucketName: string): Promise<boolean> {
  try {
    // Verificar se o bucket existe
    const { data: bucket, error: getBucketError } = await supabase.storage.getBucket(bucketName);

    if (getBucketError) {
      // Tentar criar o bucket
      console.log(`Criando bucket ${bucketName}...`);
      const { error: createError } = await supabase.storage.createBucket(bucketName, {
        public: true,
        allowedMimeTypes: ['image/*', 'video/*'], // Suportar imagens e vídeos
        fileSizeLimit: 52428800 // 50MB para suportar vídeos
      });

      if (createError) {
        console.error(`Erro ao criar bucket ${bucketName}:`, createError);
        return false;
      }
    } else if (!bucket.public) {
      // Tornar o bucket público se não for
      console.log(`Tornando bucket ${bucketName} público...`);
      await supabase.storage.updateBucket(bucketName, { public: true });
    }

    return true;
  } catch (error) {
    console.error(`Erro ao verificar/criar bucket ${bucketName}:`, error);
    return false;
  }
}

