        };
      } catch (error) {
        return {
          instagram: "",
          facebook: "",
          pinterest: "",
        };
      }
    },
  });

  return {
    instagram: socialSettings?.instagram || "",
    facebook: socialSettings?.facebook || "",
    pinterest: socialSettings?.pinterest || "",
    isLoading,
  };
}

