export const supabase = createClient(supabaseUrl, supabaseAnonKey);

// Helper function to compress and convert image to WebP format
async function compressAndConvertToWebP(file: File): Promise<File> {
  try {
    // Compression options
    const options = {
      maxSizeMB: 1, // Maximum file size in MB
      maxWidthOrHeight: 1920, // Maximum width or height
      useWebWorker: true,
      fileType: 'image/webp' as const,
      initialQuality: 0.85, // 85% quality for good balance
    };

    // Compress and convert to WebP
    const compressedFile = await imageCompression(file, options);

    // Ensure the file has the correct WebP extension and name
    const webpFileName = file.name.replace(/\.[^/.]+$/, '.webp');
    const webpFile = new File([compressedFile], webpFileName, {
      type: 'image/webp',
      lastModified: Date.now()
    });

    console.log(`Image compressed: ${(file.size / 1024).toFixed(1)}KB → ${(webpFile.size / 1024).toFixed(1)}KB`);
    return webpFile;
  } catch (error) {
    console.error('Compression failed:', error);
    throw error;
  }
}

// Helper function to sanitize file names for Supabase Storage
function sanitizeFileName(fileName: string): string {
  return fileName
    .toLowerCase()
    // Remove or replace special characters
    .replace(/[áàâãäå]/g, 'a')
    .replace(/[éèêë]/g, 'e')
    .replace(/[íìîï]/g, 'i')
    .replace(/[óòôõö]/g, 'o')
    .replace(/[úùûü]/g, 'u')
    .replace(/[ç]/g, 'c')
    .replace(/[ñ]/g, 'n')
    // Replace spaces and special chars with underscores
    .replace(/[\s\-\(\)\.]/g, '_')
    // Remove any remaining special characters
    .replace(/[^a-z0-9_]/g, '')
    // Replace multiple underscores with single
    .replace(/_+/g, '_')
    // Remove leading/trailing underscores
    .replace(/^_|_$/g, '');
}

// Helper function for uploading files to Supabase Storage with category organization and WebP conversion
export async function uploadFileToSupabase(
  file: File, 
  bucket: string, 
  path: string,
  categoryName?: string
): Promise<{ url: string; error: null } | { url: null; error: string }> {
  try {
    let processedFile = file;
    let finalPath = path;

    // Handle different file types appropriately
    if (file.type === 'video/webm') {
      // For WebM files, send directly to backend without conversion
      console.log(`Detectado arquivo WebM: ${file.name} (${file.type}) - upload direto`);
      processedFile = file; // Send original WebM file without any processing
      finalPath = sanitizeFileName(path);
    } else if (file.type === 'video/mp4' || file.type === 'image/gif') {
      // For MP4 and GIF files, let backend handle conversion to WebM
      console.log(`Detectado arquivo para conversão WebM: ${file.name} (${file.type})`);
      processedFile = file; // Send original file to backend for conversion

      // Backend will convert and change extension, so we keep original name for now
      finalPath = sanitizeFileName(path);
    } else if (file.type.startsWith('image/')) {
      // Compress and convert to WebP for other images
      try {
        console.log(`Comprimindo e convertendo ${file.name} para WebP...`);
        processedFile = await compressAndConvertToWebP(file);
        console.log(`Compressão bem-sucedida: ${processedFile.name}`);

        // Update path to use WebP extension and sanitized name
        const sanitizedName = sanitizeFileName(file.name.replace(/\.[^/.]+$/, ''));
        finalPath = `${sanitizedName}_${Date.now()}.webp`;
      } catch (compressionError) {
        console.warn('Falha na compressão/conversão para WebP, usando arquivo original:', compressionError);
        // Sanitize original filename
        finalPath = sanitizeFileName(path);
      }
    } else {
      // For other file types, use as-is
      finalPath = sanitizeFileName(path);
    }

    // Use videos bucket for video files
    if (file.type === 'video/webm' || file.type === 'video/mp4') {
      bucket = 'videos';
    }

    // Organize by category in uploads folder
    if (categoryName && bucket === 'images') {
      // Convert category name to folder-safe format
      const categoryFolder = categoryName.toLowerCase()
        .replace(/\s+/g, '')            // remove spaces
        .replace(/[áàâãäå]/g, 'a')
        .replace(/[éèêë]/g, 'e')
        .replace(/[íìîï]/g, 'i')
        .replace(/[óòôõö]/g, 'o')
        .replace(/[úùûü]/g, 'u')
        .replace(/[ç]/g, 'c')
        .replace(/[^a-z0-9]/g, '');     // remove any remaining special chars

      // Extract filename from path
      const fileName = finalPath.split('/').pop() || finalPath;
      finalPath = `uploads/${fileName}`;
    }

    console.log(`Uploading to Supabase: ${bucket}/${finalPath} (${(processedFile.size / 1024).toFixed(1)}KB)`);

    // Try upload via backend API first (bypasses RLS policies)
    try {
      const formData = new FormData();
      formData.append('file', processedFile);
      formData.append('bucket', bucket);
      formData.append('path', finalPath);

      const response = await fetch('/api/upload', {
        method: 'POST',
        body: formData,
      });

      if (response.ok) {
        const result = await response.json();
        console.log(`Upload via API successful: ${result.url}`);
        return { url: result.url, error: null };
      }
    } catch (apiError) {
      console.warn('Upload via API failed, trying direct:', apiError);
    }

    // Fallback to direct upload
    const { data, error } = await supabase.storage
      .from(bucket)
      .upload(finalPath, processedFile, {
        cacheControl: '3600',
        upsert: true
      });

    if (error) {
      console.error('Erro no upload:', error.message);
      return { url: null, error: error.message };
    }

    // Get the public URL
    const { data: { publicUrl } } = supabase.storage
      .from(bucket)
      .getPublicUrl(finalPath);

    console.log(`Upload successful: ${publicUrl}`);
    return { url: publicUrl, error: null };
  } catch (error) {
    console.error('Erro geral no upload:', error);
    return { 
      url: null, 
      error: error instanceof Error ? error.message : 'Unknown upload error' 
    };
  }
}

// Helper function to check Supabase connection
export async function checkSupabaseConnection(): Promise<boolean> {
  try {
    const { data, error } = await supabase
      .from('users')
      .select('id')
      .limit(1);

    return !error;
  } catch (error) {
    console.error('Supabase connection check failed:', error);
    return false;
  }
}

// Helper function to ensure image bucket exists
export async function ensureImageBucket(bucketName: string = 'images'): Promise<boolean> {
  try {
    // Check if bucket exists
    const { data: buckets, error: listError } = await supabase.storage.listBuckets();

    if (listError) {
      console.error('Error listing buckets:', listError);
      return false;
    }

    const bucketExists = buckets?.some(bucket => bucket.name === bucketName);

    if (bucketExists) {
      return true;
    }

    // Create bucket if it doesn't exist
    const { error: createError } = await supabase.storage.createBucket(bucketName, {
      public: true,
      allowedMimeTypes: ['image/png', 'image/jpeg', 'image/jpg', 'image/webp', 'image/svg+xml'],
      fileSizeLimit: 10485760, // 10MB
    });

    if (createError) {
      console.error('Error creating bucket:', createError);
      return false;
    }

    return true;
  } catch (error) {
    console.error('Error ensuring image bucket:', error);
    return false;
  }
}

