            </div>

            {/* Botão Filtros */}
            <div className="flex flex-col justify-end">
              <Button
                variant="outline"
                size="default"
                onClick={() => setShowMobileFilters(!showMobileFilters)}
                className="h-10 px-4 flex items-center gap-2 bg-[#191c2c] hover:bg-[#14182a] text-white border-[#191c2c]"
              >
                <Filter className="h-4 w-4" />
                <span className="text-sm font-medium">Filtros</span>
              </Button>
            </div>
          </div>

          {/* Filtros Expandidos */}
          {showMobileFilters && (
            <div className="border-t pt-4 space-y-4">
              {/* Filtro de Categoria */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Categoria
                </label>
                <Select value={selectedCategory} onValueChange={setSelectedCategory}>
                  <SelectTrigger>
                    <SelectValue placeholder="Todas as categorias" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Todas as categorias</SelectItem>
                    {categories.map((category) => (
                      <SelectItem key={category.id} value={category.id.toString()}>
                        {category.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Filtro de Formato */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Formato
                </label>
                <Select value={selectedFormat} onValueChange={setSelectedFormat}>
                  <SelectTrigger>
                    <SelectValue placeholder="Todos os formatos" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Todos os formatos</SelectItem>
                    {availableFormats.map((format) => (
                      <SelectItem key={format} value={format}>
                        {format}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Filtro de Tipo */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Tipo
                </label>
                <Select value={selectedType} onValueChange={setSelectedType}>
                  <SelectTrigger>
                    <SelectValue placeholder="Todos os tipos" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Todos os tipos</SelectItem>
                    <SelectItem value="free">
                      <div className="flex items-center">
                        <Star className="h-4 w-4 mr-2 text-gray-400" />
                        Gratuito
                      </div>
                    </SelectItem>
                    <SelectItem value="premium">
                      <div className="flex items-center">
                        <Crown className="h-4 w-4 mr-2 text-yellow-500" />
                        Premium
                      </div>
                    </SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* Ordenação */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Ordenar por
                </label>
                <Select value={sortOrder} onValueChange={setSortOrder}>
                  <SelectTrigger>
                    <SelectValue placeholder="Ordenação" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="recent">Mais recentes</SelectItem>
                    <SelectItem value="oldest">Mais antigos</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* Botão Fechar Filtros */}
              <div className="pt-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setShowMobileFilters(false)}
                  className="w-full flex items-center justify-center gap-2"
                >
                  <X className="h-4 w-4" />
                  Fechar Filtros
                </Button>
              </div>
            </div>
          )}
        </div>

        {/* Informações dos resultados */}
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-4">
            <Badge variant="outline" className="px-3 py-1">
              {filteredPosts.length} resultados
            </Badge>
            {selectedCategory !== "all" && (
              <Badge variant="secondary">
                Categoria: {categories.find(c => c.id.toString() === selectedCategory)?.name}
              </Badge>
            )}
            {selectedFormat !== "all" && (
              <Badge variant="secondary">Formato: {selectedFormat}</Badge>
            )}
            {selectedType !== "all" && (
              <Badge variant="secondary">
                Tipo: {selectedType === "premium" ? "Premium" : "Gratuito"}
              </Badge>
            )}
          </div>
        </div>

        {/* Grid de Posts */}
        {paginatedPosts.length > 0 ? (
          <div className="flex gap-4">
            {columnArrays.map((columnPosts, columnIndex) => (
              <div key={columnIndex} className="flex-1 space-y-4">
                {columnPosts.map((post) => (
                  <ArtworkCard
                    key={`${post.id}-${post.formato}`}
                    artwork={{
                      id: post.id,
                      title: post.title,
                      description: post.description,
                      imageUrl: post.imageUrl,
                      createdAt: post.createdAt,
                      isPro: post.isPro,
                      format: post.formato || 'Feed',
                      category: post.categoryId ? `Categoria ${post.categoryId}` : null
                    }}
                  />
                ))}
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <ImageIcon className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">
              Nenhuma arte encontrada
            </h3>
            <p className="text-gray-600 mb-4">
              Tente ajustar os filtros para ver mais resultados.
            </p>
            <Button 
              onClick={() => {
                setSelectedCategory("all");
                setSelectedFormat("all");
                setSelectedType("all");
                setSearchTerm("");
              }}
              variant="outline"
            >
              Limpar filtros
            </Button>
          </div>
        )}

        {/* Paginação */}
        {totalPages > 1 && (
          <div className="flex items-center justify-center space-x-2 mt-16">
            <Button
              variant="outline"
              size="sm"
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
            >
              <ChevronLeft className="h-4 w-4" />
              Anterior
            </Button>

            {/* Números das páginas */}
            {Array.from({ length: Math.min(totalPages, 5) }, (_, i) => {
              let pageNum;
              if (totalPages <= 5) {
                pageNum = i + 1;
              } else if (currentPage <= 3) {
                pageNum = i + 1;
              } else if (currentPage >= totalPages - 2) {
                pageNum = totalPages - 4 + i;
              } else {
                pageNum = currentPage - 2 + i;
              }

              return (
                <Button
                  key={pageNum}
                  variant={currentPage === pageNum ? "default" : "outline"}
                  size="sm"
                  onClick={() => handlePageChange(pageNum)}
                  className={currentPage === pageNum ? "bg-[#191c2c] hover:bg-[#14182a] text-white border-[#191c2c]" : ""}
                >
                  {pageNum}
                </Button>
              );
            })}

            <Button
              variant="outline"
              size="sm"
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="bg-[#191c2c] hover:bg-[#14182a] text-white border-[#191c2c] hover:border-[#14182a] disabled:bg-gray-300 disabled:text-gray-500 disabled:border-gray-300"
            >
              Próxima
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

