                      ) : (() => {
                        // Priorizar data de início da assinatura Hotmart
                        if (userPlan?.startDate) {
                          return new Date(userPlan.startDate).toLocaleDateString('pt-BR', {
                            day: '2-digit',
                            month: '2-digit', 
                            year: 'numeric'
                          });
