import { useAuth } from "@/hooks/use-auth";
import { useQuery } from "@tanstack/react-query";
import { Users, Search, User, Eye } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Link } from "wouter";
import { Skeleton } from "@/components/ui/skeleton";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ProfileLayout } from "@/components/layout/ProfileLayout";

interface FollowedUser {
  id: number;
  username: string;
  profileImage?: string;
  postsCount: number;
  isDesigner: boolean;
}

export default function SeguindoPage() {
  const { user } = useAuth();

  // Buscar usuários que o usuário atual está seguindo
  const { data: followedUsers = [], isLoading } = useQuery<FollowedUser[]>({
    queryKey: ['/api/user/following'],
    enabled: !!user,
    staleTime: 5 * 60 * 1000, // 5 minutos em cache
    retry: 1
  });

  if (isLoading) {
    return (
      <ProfileLayout>
        <div className="max-w-7xl">
          <div className="mb-6">
            <h1 className="text-2xl lg:text-3xl font-bold tracking-tight flex items-center gap-2 lg:gap-3">
              <div className="w-8 h-8 lg:w-10 lg:h-10 rounded-full bg-blue-50 flex items-center justify-center">
                <Users className="w-4 h-4 lg:w-6 lg:h-6 text-blue-500" />
              </div>
              Seguindo
            </h1>
            <p className="text-muted-foreground mt-2 text-sm lg:text-base">
              Designers e autores que você está seguindo
            </p>
          </div>

          {/* Loading skeleton */}
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {Array.from({ length: 8 }).map((_, i) => (
            <Card key={i} className="p-6">
              <div className="flex flex-col items-center space-y-4">
                <Skeleton className="h-16 w-16 rounded-full" />
                <Skeleton className="h-4 w-24" />
                <Skeleton className="h-3 w-16" />
                <Skeleton className="h-8 w-20" />
              </div>
            </Card>
          ))}
          </div>
        </div>
      </ProfileLayout>
    );
  }

  return (
    <ProfileLayout>
      <div className="max-w-7xl">
        <div className="mb-6">
          <h1 className="text-2xl lg:text-3xl font-bold tracking-tight flex items-center gap-2 lg:gap-3">
            <div className="w-8 h-8 lg:w-10 lg:h-10 rounded-full bg-blue-50 flex items-center justify-center">
              <Users className="w-4 h-4 lg:w-6 lg:h-6 text-blue-500" />
          </div>
          Seguindo
            </h1>
            <p className="text-muted-foreground mt-2 text-sm lg:text-base">
              Designers e autores que você está seguindo
            </p>
          </div>

        {followedUsers.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 lg:py-16 text-center">
            <div className="w-16 h-16 lg:w-20 lg:h-20 rounded-full bg-blue-50 flex items-center justify-center mb-4 lg:mb-6">
              <Users className="w-8 h-8 lg:w-10 lg:h-10 text-blue-300" />
            </div>
            <h2 className="text-xl lg:text-2xl font-semibold text-gray-800 mb-2">
              Você ainda não está seguindo ninguém
            </h2>
            <p className="text-gray-600 mb-6 lg:mb-8 max-w-md text-sm lg:text-base">
              Siga designers para ver mais artes como essas e acompanhar os trabalhos dos seus criadores favoritos!
            </p>
            <Link href="/">
              <Button className="bg-[#1f4ed8] hover:bg-[#1d4ed8]/90 text-white">
                <Search className="w-4 h-4 mr-2" />
                Explorar artes
              </Button>
            </Link>
          </div>
        ) : (
          <div>
            <div className="mb-6">
              <p className="text-sm text-gray-600">
                {followedUsers.length} {followedUsers.length === 1 ? 'pessoa seguida' : 'pessoas seguidas'}
              </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 lg:gap-6">
            {followedUsers.map((followedUser) => (
              <Card key={followedUser.id} className="hover:shadow-lg transition-shadow duration-200">
                <CardContent className="p-6">
                  <div className="flex flex-col items-center space-y-4">
                    {/* Avatar do designer */}
                    <Avatar className="h-16 w-16">
                      <AvatarImage 
                        src={followedUser.profileImage} 
                        alt={followedUser.username}
