              <Eye className="h-12 w-12 mx-auto mb-4" />
              <p>Configure o conteúdo para ver o preview</p>
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-4 rounded border">
        <h4 className="font-medium mb-3">Configurações do Popup</h4>
