                  ) : (
                    hasCustomLogo ? (
                      <img 
                        src={logoUrl} 
                        alt="Logo" 
                        className="h-6 w-6 object-contain"
                        onError={(e) => {
                          const target = e.target as HTMLImageElement;
                          target.style.display = 'none';
                          target.insertAdjacentHTML('afterend', 'DE');
                        }}
                      />
                    ) : (
                      "DE"
                    )
                  )}
                </div>
              </Link>
            </div>

            {/* Botão para recolher a sidebar */}
            <Button 
              variant="ghost" 
              size="icon" 
              onClick={onToggle}
              className="h-6 w-6"
            >
              {isOpen ? <ChevronLeft className="h-4 w-4" /> : <Menu className="h-4 w-4" />}
            </Button>
          </div>

          {/* Perfil do usuário */}
          <div className={cn(
            "flex items-center gap-3 p-4 border-b",
            !isOpen && "justify-center"
          )}>
            <Avatar className="h-10 w-10">
              <AvatarImage 
                src={userData?.profileImage || ""} 
                alt={userData?.username || "Admin"}
                className="object-cover"
              />
              <AvatarFallback>
                {userData?.username?.slice(0, 2)?.toUpperCase() || "AD"}
              </AvatarFallback>
            </Avatar>

            {isOpen && (
              <div className="overflow-hidden">
                <p className="text-sm font-medium truncate">
                  {userData?.username || "Admin"}
                </p>
                <p className="text-xs text-muted-foreground truncate">
                  {userData?.email || "admin@example.com"}
                </p>
              </div>
            )}
          </div>

          {/* Links de navegação */}
          <nav className="flex-1 overflow-y-auto py-4 px-2">
            <ul className="space-y-1">
              {menuItems.map((item) => (
                <li key={item.id}>
                  {item.hasSubmenu ? (
                    // Item com submenu
                    <div>
                      <Button
                        variant="ghost"
                        onClick={() => toggleSubmenu(item.id)}
                        className={cn(
                          "w-full justify-start",
                          !isOpen && "md:justify-center"
                        )}
                        size="sm"
                      >
                        <span className={cn(
                          "mr-2",
                          "text-muted-foreground",
                          !isOpen && "md:mr-0"
                        )}>
                          {item.icon}
                        </span>
                        {isOpen && (
                          <>
                            <span className="flex-1 text-left">{item.label}</span>
                            {expandedMenus.includes(item.id) ? 
                              <ChevronDown className="h-4 w-4" /> : 
                              <ChevronRight className="h-4 w-4" />
                            }
                          </>
                        )}
                      </Button>

                      {/* Submenu items */}
                      {isOpen && expandedMenus.includes(item.id) && item.subItems && (
                        <div className="ml-4 mt-1 space-y-1">
                          {item.subItems.map((subItem) => (
                            <Button
                              key={subItem.id}
                              variant={isActive(subItem.path) ? "default" : "ghost"}
                              className={cn(
                                "w-full justify-start text-sm",
                                isActive(subItem.path) ? "bg-primary/10 text-primary hover:bg-primary/15" : ""
                              )}
                              size="sm"
                              onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                setLocation(subItem.path);
                              }}
                            >
                              <span className={cn(
                                "mr-2",
                                isActive(subItem.path) ? "text-primary" : "text-muted-foreground"
                              )}>
                                {subItem.icon}
                              </span>
                              <span>{subItem.label}</span>
                            </Button>
                          ))}
                        </div>
                      )}
                    </div>
                  ) : (
                    // Item normal sem submenu
                    <Link href={item.path}>
                      <Button
                        variant={isActive(item.path) ? "default" : "ghost"}
                        className={cn(
                          "w-full justify-start",
                          isActive(item.path) ? "bg-primary/10 text-primary hover:bg-primary/15" : "",
                          !isOpen && "md:justify-center"
                        )}
                        size="sm"
                      >
                        <span className={cn(
                          "mr-2",
                          isActive(item.path) ? "text-primary" : "text-muted-foreground",
                          !isOpen && "md:mr-0"
                        )}>
                          {item.icon}
                        </span>
                        {isOpen && <span>{item.label}</span>}
                      </Button>
                    </Link>
                  )}

                  {item.separator && (
                    <div>
                      {isOpen && <Separator className="my-4" />}
                      {!isOpen && <div className="my-4" />}
                    </div>
                  )}
                </li>
              ))}
            </ul>
          </nav>

          {/* Rodapé da sidebar */}
          <div className="p-4 mt-auto">
            {isOpen && (
              <div className="text-xs text-center text-muted-foreground">
                <p>Design para Estética</p>
                <p className="mt-1">v1.0.0</p>
              </div>
            )}
          </div>
        </div>
      </aside>
    </>
  );
}

